import { Pool } from 'pg';

interface DomainEvent {
  aggregateId: string;
  eventType: string;
  payload: unknown;
  version: number;
  timestamp: Date;
}

export class EventStore {
  constructor(private pool: Pool) {}

  async append(event: Omit<DomainEvent, 'timestamp'>): Promise<void> {
    await this.pool.query(
      'INSERT INTO domain_events (aggregate_id, event_type, payload, version, timestamp) VALUES ($1, $2, $3, $4, NOW())',
      [event.aggregateId, event.eventType, JSON.stringify(event.payload), event.version],
    );
  }

  async getEvents(aggregateId: string, afterVersion = 0): Promise<DomainEvent[]> {
    const result = await this.pool.query(
      'SELECT * FROM domain_events WHERE aggregate_id = $1 AND version > $2 ORDER BY version ASC',
      [aggregateId, afterVersion],
    );
    return result.rows;
  }

  async getLatestVersion(aggregateId: string): Promise<number> {
    const result = await this.pool.query(
      'SELECT COALESCE(MAX(version), 0) as version FROM domain_events WHERE aggregate_id = $1',
      [aggregateId],
    );
    return result.rows[0].version;
  }
}

