import { EventStore } from './event-store';
import { EVENTS, OrderCreatedEvent } from '../../../src/shared/events';

interface OrderState {
  id: string;
  status: 'created' | 'paid' | 'shipped' | 'cancelled';
  items: Array<{ productId: string; quantity: number; price: number }>;
  total: number;
}

export class OrderAggregate {
  private state: OrderState | null = null;
  private version = 0;

  constructor(private eventStore: EventStore, private id: string) {}

  async load(): Promise<void> {
    const events = await this.eventStore.getEvents(this.id);
    for (const event of events) {
      this.apply(event.eventType, event.payload);
      this.version = event.version;
    }
  }

  async create(userId: string, items: OrderState['items']): Promise<void> {
    const total = items.reduce((sum, item) => sum + item.price * item.quantity, 0);
    await this.eventStore.append({
      aggregateId: this.id,
      eventType: EVENTS.ORDER_CREATED,
      payload: { orderId: this.id, userId, items, total, timestamp: new Date().toISOString() } satisfies OrderCreatedEvent,
      version: this.version + 1,
    });
  }

  private apply(eventType: string, payload: unknown): void {
    switch (eventType) {
      case EVENTS.ORDER_CREATED: {
        const e = payload as OrderCreatedEvent;
        this.state = { id: e.orderId, status: 'created', items: e.items, total: e.total };
        break;
      }
      case EVENTS.ORDER_PAID:
        if (this.state) this.state.status = 'paid';
        break;
      case EVENTS.ORDER_SHIPPED:
        if (this.state) this.state.status = 'shipped';
        break;
      case EVENTS.ORDER_CANCELLED:
        if (this.state) this.state.status = 'cancelled';
        break;
    }
  }
}

