import amqplib from 'amqplib';
import { withRetry, CRITICAL_RETRY } from '../../../src/shared/retry-policy';

let connection: amqplib.Connection | null = null;
let channel: amqplib.Channel | null = null;

const EXCHANGE_NAME = 'domain_events';
const EXCHANGE_TYPE = 'topic';

export async function initPublisher(url: string): Promise<void> {
  connection = await withRetry(() => amqplib.connect(url), CRITICAL_RETRY);
  channel = await connection.createChannel();
  await channel.assertExchange(EXCHANGE_NAME, EXCHANGE_TYPE, { durable: true });
}

export async function publishEvent(routingKey: string, payload: unknown): Promise<void> {
  if (!channel) throw new Error('Publisher not initialized');
  channel.publish(
    EXCHANGE_NAME,
    routingKey,
    Buffer.from(JSON.stringify(payload)),
    { persistent: true, contentType: 'application/json', timestamp: Date.now() },
  );
}

export async function shutdown(): Promise<void> {
  await channel?.close();
  await connection?.close();
}

